import heroImage from "../assets/images/main.svg";

export default function Hero() {
    return (
        <div className="container-fluid">
            <div className="card">
                <div className="card-header">
                    <img src={ heroImage } alt="gambar hero" className="hero-image" />
                </div>
            </div>
        </div>
    )
}
